#!/bin/bash
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
LIB_DIR="$SCRIPT_DIR/lib"

mkdir -p "$LIB_DIR"

# Match Odin's macOS deployment target (16.0) to suppress linker warnings.
# Apple clang on macOS 26+ forcibly overrides -mmacosx-version-min to the SDK
# version, so we prefer Homebrew LLVM/clang which respects the flag.
# MACOS_MIN overrides the target — CI sets 13.0 for portable release binaries
# (a 16.0-minos binary would not run on the macOS 15 GitHub runners).
DEPLOY_FLAGS="-mmacosx-version-min=${MACOS_MIN:-16.0}"
if [ "$(uname -s)" = "Darwin" ]; then
    if [ -x /opt/homebrew/opt/llvm@20/bin/clang ]; then
        CC="${CC:-/opt/homebrew/opt/llvm@20/bin/clang}"
        CXX="${CXX:-/opt/homebrew/opt/llvm@20/bin/clang++}"
    elif [ -x /opt/homebrew/opt/llvm/bin/clang ]; then
        CC="${CC:-/opt/homebrew/opt/llvm/bin/clang}"
        CXX="${CXX:-/opt/homebrew/opt/llvm/bin/clang++}"
    else
        CC="${CC:-cc}"
        CXX="${CXX:-c++}"
    fi
else
    CC="${CC:-cc}"
    CXX="${CXX:-c++}"
    DEPLOY_FLAGS=""
fi

echo "=== Building RIPEMD-160 ==="
$CC -c -O2 $DEPLOY_FLAGS -o "$SCRIPT_DIR/ripemd160/ripemd160.o" "$SCRIPT_DIR/ripemd160/ripemd160.c"
ar rcs "$LIB_DIR/libripemd160.a" "$SCRIPT_DIR/ripemd160/ripemd160.o"
rm "$SCRIPT_DIR/ripemd160/ripemd160.o"
echo "Built libripemd160.a"

echo "=== Building LevelDB ==="
LEVELDB_DIR="$SCRIPT_DIR/leveldb"
CXXFLAGS="-O2 -DNDEBUG -DLEVELDB_PLATFORM_POSIX $DEPLOY_FLAGS -I$LEVELDB_DIR -I$LEVELDB_DIR/include"

# Generate port_config.h from template (submodule only ships .h.in).
if [ ! -f "$LEVELDB_DIR/port/port_config.h" ]; then
    cat > "$LEVELDB_DIR/port/port_config.h" << 'PORTCFG'
// Auto-generated by build.sh for POSIX builds (macOS + Linux).
#ifndef STORAGE_LEVELDB_PORT_PORT_CONFIG_H_
#define STORAGE_LEVELDB_PORT_PORT_CONFIG_H_
#if !defined(HAVE_FDATASYNC)
#if defined(__linux__)
#define HAVE_FDATASYNC 1
#else
#define HAVE_FDATASYNC 0
#endif
#endif
#if !defined(HAVE_FULLFSYNC)
#if defined(__APPLE__)
#define HAVE_FULLFSYNC 1
#else
#define HAVE_FULLFSYNC 0
#endif
#endif
#if !defined(HAVE_O_CLOEXEC)
#define HAVE_O_CLOEXEC 1
#endif
#if !defined(HAVE_CRC32C)
#define HAVE_CRC32C 0
#endif
#if !defined(HAVE_SNAPPY)
#define HAVE_SNAPPY 0
#endif
#endif  // STORAGE_LEVELDB_PORT_PORT_CONFIG_H_
PORTCFG
    echo "Generated port_config.h"
fi

SOURCES="db/builder.cc db/c.cc db/db_impl.cc db/db_iter.cc db/dbformat.cc
  db/dumpfile.cc db/filename.cc db/log_reader.cc db/log_writer.cc
  db/memtable.cc db/repair.cc db/table_cache.cc db/version_edit.cc
  db/version_set.cc db/write_batch.cc table/block.cc table/block_builder.cc
  table/filter_block.cc table/format.cc table/iterator.cc table/merger.cc
  table/table.cc table/table_builder.cc table/two_level_iterator.cc
  util/arena.cc util/bloom.cc util/cache.cc util/coding.cc util/comparator.cc
  util/crc32c.cc util/env.cc util/env_posix.cc util/filter_policy.cc
  util/hash.cc util/logging.cc util/options.cc util/status.cc"

OBJS=""
for src in $SOURCES; do
    obj="$LEVELDB_DIR/${src%.cc}.o"
    mkdir -p "$(dirname "$obj")"
    $CXX $CXXFLAGS -std=c++17 -c "$LEVELDB_DIR/$src" -o "$obj"
    OBJS="$OBJS $obj"
done
ar rcs "$LIB_DIR/libleveldb.a" $OBJS
for obj in $OBJS; do rm -f "$obj"; done
echo "Built libleveldb.a"

echo "=== Building SHA-256 (Bitcoin Core multi-backend) ==="
SHA256_DIR="$SCRIPT_DIR/sha256"
SHA256_CXXFLAGS="-O2 -DNDEBUG -std=c++20 $DEPLOY_FLAGS -I$SHA256_DIR/include"
SHA256_OBJS=""

# Detect architecture for SIMD flags
ARCH="$(uname -m)"

# Main sha256.cpp — generic + dispatch (always enable all backends at compile time;
# runtime CPUID selects the right one)
if [ "$ARCH" = "x86_64" ] || [ "$ARCH" = "amd64" ]; then
    $CXX $SHA256_CXXFLAGS -DENABLE_SSE41 -DENABLE_AVX2 -DENABLE_X86_SHANI \
        -c "$SHA256_DIR/sha256.cpp" -o "$SHA256_DIR/sha256.o"
elif [ "$ARCH" = "arm64" ] || [ "$ARCH" = "aarch64" ]; then
    $CXX $SHA256_CXXFLAGS -DENABLE_ARM_SHANI \
        -c "$SHA256_DIR/sha256.cpp" -o "$SHA256_DIR/sha256.o"
else
    $CXX $SHA256_CXXFLAGS \
        -c "$SHA256_DIR/sha256.cpp" -o "$SHA256_DIR/sha256.o"
fi
SHA256_OBJS="$SHA256_OBJS $SHA256_DIR/sha256.o"

# SSE4/SSE4.1 — x86 inline asm, no special compiler flags needed (uses asm blocks)
if [ "$ARCH" = "x86_64" ] || [ "$ARCH" = "amd64" ]; then
    $CXX $SHA256_CXXFLAGS \
        -c "$SHA256_DIR/sha256_sse4.cpp" -o "$SHA256_DIR/sha256_sse4.o"
    SHA256_OBJS="$SHA256_OBJS $SHA256_DIR/sha256_sse4.o"

    # SSE4.1 4-way — needs -msse4.1
    $CXX $SHA256_CXXFLAGS -DENABLE_SSE41 -msse4.1 \
        -c "$SHA256_DIR/sha256_sse41.cpp" -o "$SHA256_DIR/sha256_sse41.o"
    SHA256_OBJS="$SHA256_OBJS $SHA256_DIR/sha256_sse41.o"

    # AVX2 — needs -mavx2
    $CXX $SHA256_CXXFLAGS -DENABLE_AVX2 -mavx2 \
        -c "$SHA256_DIR/sha256_avx2.cpp" -o "$SHA256_DIR/sha256_avx2.o"
    SHA256_OBJS="$SHA256_OBJS $SHA256_DIR/sha256_avx2.o"

    # x86 SHA-NI — needs -msse4.1 -msha
    $CXX $SHA256_CXXFLAGS -DENABLE_SSE41 -DENABLE_X86_SHANI -msse4.1 -msha \
        -c "$SHA256_DIR/sha256_x86_shani.cpp" -o "$SHA256_DIR/sha256_x86_shani.o"
    SHA256_OBJS="$SHA256_OBJS $SHA256_DIR/sha256_x86_shani.o"
fi

# ARM SHA — needs crypto extensions
if [ "$ARCH" = "arm64" ] || [ "$ARCH" = "aarch64" ]; then
    ARM_SHA_FLAGS=""
    # Apple Silicon has SHA built-in, no extra flags needed
    # Linux ARM may need -march=armv8-a+crypto
    if [ "$(uname -s)" != "Darwin" ]; then
        ARM_SHA_FLAGS="-march=armv8-a+crypto"
    fi
    $CXX $SHA256_CXXFLAGS -DENABLE_ARM_SHANI $ARM_SHA_FLAGS \
        -c "$SHA256_DIR/sha256_arm_shani.cpp" -o "$SHA256_DIR/sha256_arm_shani.o"
    SHA256_OBJS="$SHA256_OBJS $SHA256_DIR/sha256_arm_shani.o"
fi

# C wrapper
$CXX $SHA256_CXXFLAGS -I"$SHA256_DIR" \
    -c "$SHA256_DIR/sha256_c.cpp" -o "$SHA256_DIR/sha256_c.o"
SHA256_OBJS="$SHA256_OBJS $SHA256_DIR/sha256_c.o"

ar rcs "$LIB_DIR/libsha256.a" $SHA256_OBJS
for obj in $SHA256_OBJS; do rm -f "$obj"; done
echo "Built libsha256.a"

echo "=== Building libsecp256k1 ==="
cd "$SCRIPT_DIR/libsecp256k1"

if [ ! -f configure ]; then
    echo "Running autogen.sh..."
    ./autogen.sh
fi

if [ ! -f Makefile ]; then
    echo "Running configure..."
    CC="$CC" CFLAGS="$DEPLOY_FLAGS" ./configure \
        --enable-module-recovery \
        --enable-module-schnorrsig \
        --enable-module-extrakeys \
        --enable-module-ellswift \
        --disable-shared \
        --enable-static \
        --with-pic
fi

make -j"$(nproc 2>/dev/null || sysctl -n hw.ncpu)"
cp .libs/libsecp256k1.a "$LIB_DIR/libsecp256k1.a"
echo "Built libsecp256k1.a"

# RocksDB — engine for the optional --index-addresses scripthash index only
# (chainstate/block-index/txindex stay on LevelDB). Static, PORTABLE, Zstd as the
# sole compression backend (link stage uses system -lzstd; Debian/Ubuntu:
# libzstd-dev, macOS: brew install zstd). Slow to compile (~minutes), so skip when
# librocksdb.a is already present — `rm deps/lib/librocksdb.a` to force a rebuild.
echo "=== Building RocksDB (addrindex engine, static, Zstd-only) ==="
ROCKSDB_DIR="$SCRIPT_DIR/rocksdb"
ROCKSDB_TAG="v9.9.3"
if [ -f "$LIB_DIR/librocksdb.a" ]; then
    echo "librocksdb.a already present — skipping (rm to force rebuild)"
else
    if [ ! -d "$ROCKSDB_DIR" ]; then
        echo "Cloning RocksDB $ROCKSDB_TAG..."
        git clone --depth 1 --branch "$ROCKSDB_TAG" \
            https://github.com/facebook/rocksdb.git "$ROCKSDB_DIR"
    fi
    # Build with the SAME toolchain as the other deps (Homebrew LLVM on macOS),
    # PORTABLE (no -march=native, so the binary runs on any x86_64/arm64 of that
    # OS). On macOS also pin the deployment target and point CMake at Homebrew so
    # it finds libzstd (arm64: /opt/homebrew, Intel: /usr/local).
    ROCKSDB_CMAKE_ARGS=(
        -DCMAKE_BUILD_TYPE=Release
        -DPORTABLE=1
        -DROCKSDB_BUILD_SHARED=OFF
        -DWITH_ZSTD=ON -DWITH_LZ4=OFF -DWITH_SNAPPY=OFF -DWITH_GFLAGS=OFF
        -DWITH_TESTS=OFF -DWITH_TOOLS=OFF -DWITH_CORE_TOOLS=OFF
        -DWITH_BENCHMARK=OFF -DWITH_BENCHMARK_TOOLS=OFF
        -DFAIL_ON_WARNINGS=OFF
        -DCMAKE_C_COMPILER="$CC" -DCMAKE_CXX_COMPILER="$CXX"
    )
    if [ "$(uname -s)" = "Darwin" ]; then
        ROCKSDB_CMAKE_ARGS+=( -DCMAKE_OSX_DEPLOYMENT_TARGET="${MACOS_MIN:-16.0}" )
        BREW_PREFIX="$(brew --prefix 2>/dev/null || echo /opt/homebrew)"
        ROCKSDB_CMAKE_ARGS+=( -DCMAKE_PREFIX_PATH="$BREW_PREFIX" )
    fi
    cmake -S "$ROCKSDB_DIR" -B "$ROCKSDB_DIR/build" "${ROCKSDB_CMAKE_ARGS[@]}"
    cmake --build "$ROCKSDB_DIR/build" --target rocksdb \
        -j"$(nproc 2>/dev/null || sysctl -n hw.ncpu)"
    cp "$ROCKSDB_DIR/build/librocksdb.a" "$LIB_DIR/librocksdb.a"
    echo "Built librocksdb.a"
fi

echo "=== All dependencies built ==="
ls -la "$LIB_DIR"
